//! Japanese vocabulary database for Hangul→Japanese IME
//!
//! This module provides a comprehensive vocabulary database storing (surface, reading) pairs
//! organized by part of speech (POS) and semantic category. The hangul field will be
//! auto-generated later by the kana_hangul converter.

use std::collections::HashMap;

/// Part of speech enumeration
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum Pos {
    Noun,
    Verb,
    IAdjective,
    NaAdjective,
    Adverb,
    Particle,
    Conjunction,
    Expression,
    Counter,
    Suffix,
}

/// Semantic category enumeration
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum Category {
    Greeting,
    Family,
    Food,
    Nature,
    Body,
    Place,
    Time,
    Transport,
    Work,
    School,
    Shopping,
    Health,
    Hobby,
    Emotion,
    Animal,
    Color,
    Technology,
    Home,
    Culture,
    Abstract,
    Particle,
    Verb,
}

/// Vocabulary entry containing surface form, reading, POS, and category
#[derive(Clone, Debug)]
pub struct VocabEntry {
    pub surface: &'static str,
    pub reading: &'static str,
    pub pos: Pos,
    pub category: Category,
}

impl VocabEntry {
    /// Create a new vocabulary entry
    pub fn new(surface: &'static str, reading: &'static str, pos: Pos, category: Category) -> Self {
        VocabEntry {
            surface,
            reading,
            pos,
            category,
        }
    }
}

