/// Filter vocabulary entries by part of speech
pub fn filter_by_pos(vocab: &[VocabEntry], pos: Pos) -> Vec<&VocabEntry> {
    vocab.iter().filter(|entry| entry.pos == pos).collect()
}

/// Filter vocabulary entries by category
pub fn filter_by_category(vocab: &[VocabEntry], category: Category) -> Vec<&VocabEntry> {
    vocab.iter().filter(|entry| entry.category == category).collect()
}

/// Filter vocabulary entries by both POS and category
pub fn filter_by_pos_and_category(
    vocab: &[VocabEntry],
    pos: Pos,
    category: Category,
) -> Vec<&VocabEntry> {
    vocab
        .iter()
        .filter(|entry| entry.pos == pos && entry.category == category)
        .collect()
}

/// Get vocabulary statistics
pub fn get_vocab_stats(vocab: &[VocabEntry]) -> HashMap<Pos, usize> {
    let mut stats = HashMap::new();
    for entry in vocab {
        *stats.entry(entry.pos).or_insert(0) += 1;
    }
    stats
}

/// Build full vocabulary: base (731) + extended (~1200) entries
pub fn build_full_vocab() -> Vec<VocabEntry> {
    let mut vocab = build_vocab();
    vocab.extend(crate::vocab_extended::build_extended_vocab());
    vocab
}

/// Get category statistics
pub fn get_category_stats(vocab: &[VocabEntry]) -> HashMap<Category, usize> {
    let mut stats = HashMap::new();
    for entry in vocab {
        *stats.entry(entry.category).or_insert(0) += 1;
    }
    stats
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_vocab_count() {
        let vocab = build_vocab();
        assert!(vocab.len() >= 700, "Vocabulary should have at least 700 entries, got {}", vocab.len());
    }

    #[test]
    fn test_filter_by_pos() {
        let vocab = build_vocab();
        let nouns = filter_by_pos(&vocab, Pos::Noun);
        assert!(!nouns.is_empty(), "Should have at least some nouns");
    }

    #[test]
    fn test_filter_by_category() {
        let vocab = build_vocab();
        let food = filter_by_category(&vocab, Category::Food);
        assert!(!food.is_empty(), "Should have at least some food items");
    }

    #[test]
    fn test_vocab_entries_valid() {
        let vocab = build_vocab();
        for entry in &vocab {
            assert!(!entry.surface.is_empty(), "Surface form should not be empty");
            assert!(!entry.reading.is_empty(), "Reading should not be empty");
        }
    }
}
